import { useState, useEffect } from 'react';
import upload from '../lib/Write.js';

export default function Connect() {

    const nanoOldBootloader = {
        signature: Buffer.from([0x1e, 0x95, 0x0f]),
        pageSize: 128,
        timeout: 400,
        baudRate: 57600,
    }

    console.log("Got Connect")

    const [msg, set_msg] = useState("Checking Firmware...")
    const [progress, set_progress] = useState(0)
    
    function onProgress(percentage) {
        set_progress(percentage)
    }

    useEffect(()=>{
        async function handleUpload() {
            try {
                const port = await navigator.serial.requestPort();
                console.log(port)
                set_msg("Uploading New Firmware...")
                await upload(nanoOldBootloader, "https://jaxson098.github.io/Beacon-Console/firmware.hex", onProgress, true, port)
            } catch (e) {
                console.log(e)
            }
        }
        handleUpload()
    },[])

    return (
        <div className="flex flex-col items-center justify-center gap-2">
            <p className='text-xl'>{msg}</p>
            <p className='text-sm text-gray-700'>{progress}</p>
        </div>
    );
}