//code modified from: https://github.com/dbuezas/arduino-web-uploader

import { ReadableWebToNodeStream } from 'readable-web-to-node-stream'

export class Serial {
  port;
  reader;
  writer;

  async close() {
    if (this.reader) {
      const reader = this.reader
      this.reader = undefined
      // @ts-ignore
      // this is specific to the "readable-web-to-node-stream" library
      await reader.reader.cancel()
      // await this.reader.close() // this blocks if uploading failed
    }
    if (this.writer) {
      const writer = this.writer
      this.writer = undefined
      await writer.close()
    }
    if (this.port) {
      const port = this.port
      this.port = undefined
      await port.close()
    }
  }
  async connect(options, port) {
    options = {
      baudRate: 9600,
      dataBits: 8,
      stopBits: 1,
      parity: 'none',
      bufferSize: 255,
      rtscts: false,
      xon: false,
      xoff: false,
      ...options, //overwrites
    }
    if (this.port) await this.close()
    this.port = port
    await this.port.open(options)
    this.reader = new ReadableWebToNodeStream(this.port.readable)
    this.writer = this.port.writable.getWriter()

    // next I'm faking a NodeJS.ReadWriteStream
    const rwStream = this.reader
    // @ts-ignore
    rwStream.write = (buffer, onDone) => {
      this.writer.write(buffer).then(() => onDone(null), onDone)
      return true
    }
    return rwStream
  }
}
const serial = new Serial()

export default serial